UPDATE inventory
quantity = #{quantity}, frozen = #{frozen}, available = #{available}, sale_count = #{saleCount}, version = #{version}, update_time = NOW(3)
WHERE id = #{id}

UPDATE inventory
SET available = available - #{quantity},
    version = version + 1,
    update_time = NOW(3)
WHERE product_id = #{productId}
  AND available >= #{quantity}
  AND version = #{version}

UPDATE inventory
SET available = available - #{quantity},
    version = version + 1,
    update_time = NOW(3)
WHERE product_id = #{productId}
  AND available >= #{quantity}

UPDATE inventory SET available = available + #{quantity},
    update_time = NOW(3)
WHERE product_id = #{productId}

UPDATE inventory SET frozen = frozen + #{quantity},
    update_time = NOW(3)
WHERE product_id = #{productId}

UPDATE inventory SET frozen = frozen - #{quantity},
    update_time = NOW(3)
WHERE product_id = #{productId}
  AND frozen >= #{quantity}

UPDATE inventory SET quantity = quantity + #{quantity},
    update_time = NOW(3)
WHERE product_id = #{productId}

UPDATE inventory SET sale_count = sale_count + #{quantity},
    update_time = NOW(3)
WHERE product_id = #{productId}
